exercises.solution:
function makeDispatcher(strategies) {
  return {
    dispatch(type, payload) {
      if (!strategies[type]) throw new Error('Unknown strategy: ' + type);
      return strategies[type](payload);
    }
  };
}

exercises.tests:
let calls = 0;
const add = memoize((a, b) => { calls++; return a + b; });
check('returns correct result', () => {
  expect(add(2, 3)).toBe(5);
});
check('caches on repeat call', () => {
  calls = 0;
  add(2, 3); add(2, 3);
  expect(calls).toBe(0);
});
check('recomputes for new args', () => {
  calls = 0;
  add(1, 1);
  expect(calls).toBe(1);
});

exercises.solution:
function memoize(fn) {
  const cache = new Map();
  return function(...args) {
    const key = JSON.stringify(args);
    if (cache.has(key)) return cache.get(key);
    const result = fn(...args);
    cache.set(key, result);
    return result;
  };
}

