check('builds deps before dependents', () => {
  const order = topoOrder({ app: ['core'], core: [], utils: [] });
  expect(order.indexOf('core') < order.indexOf('app')).toBe(true);
});
check('handles diamond dep', () => {
  const order = topoOrder({ app: ['ui', 'core'], ui: ['core'], core: [] });
  expect(order.indexOf('core') < order.indexOf('ui')).toBe(true);
  expect(order.indexOf('core') < order.indexOf('app')).toBe(true);
});
check('throws on cycle', () => {
  expect(() => topoOrder({ a: ['b'], b: ['a'] })).toThrow();
});

exercises.solution:
function topoOrder(graph) {
  const state = {}; // 0=unvisited, 1=in-progress, 2=done
  const out = [];
  function visit(n) {
    if (state[n] === 1) throw new Error('Cycle detected at ' + n);
    if (state[n] === 2) return;
    state[n] = 1;
    (graph[n] || []).forEach(visit);
    state[n] = 2;
    out.push(n);
  }
  Object.keys(graph).forEach(visit);
  return out;
}

