const dag = {
  d: ['c'],
  c: ['b'],
  b: ['a'],
  a: []
};
check('direct parent is ancestor', () => {
  expect(isAncestor(dag, 'c', 'd')).toBe(true);
});
check('grandparent is ancestor', () => {
  expect(isAncestor(dag, 'a', 'd')).toBe(true);
});
check('descendant is not ancestor of ancestor', () => {
  expect(isAncestor(dag, 'd', 'a')).toBe(false);
});
check('same commit is its own ancestor', () => {
  expect(isAncestor(dag, 'b', 'b')).toBe(true);
});

exercises.solution:
function isAncestor(parentMap, ancestor, descendant) {
  const visited = new Set();
  const queue = [descendant];
  while (queue.length) {
    const curr = queue.shift();
    if (curr === ancestor) return true;
    if (visited.has(curr)) continue;
    visited.add(curr);
    (parentMap[curr] || []).forEach(p => queue.push(p));
  }
  return false;
}
